    const fetchTelegramJson = useCallback(async (url, timeoutMs = 5000)=>{
        const controller = new AbortController();
        const timeoutId = window.setTimeout(()=>controller.abort(), timeoutMs);
        try {
            const resp = await fetch(url, {
                signal: controller.signal
            });
            return await resp.json();
        } finally{
            window.clearTimeout(timeoutId);
        }
    }, []);
    const refreshBotStatus = useCallback(async (token, options)=>{
        const tkn = token || globalConfig.telegramBotToken;
        if (!tkn) return;
        if (options?.silent && botRefreshInFlightRef.current) return;
        botRefreshInFlightRef.current = true;
        if (!options?.silent) setBotStatus((prev)=>({
                ...prev,
                loading: true
            }));
        try {
            const shouldRefreshIdentity = !options?.silent || !botStatus.botId || botIdentityChecksRef.current >= 6;
            const [whData, meData] = await Promise.all([
                fetchTelegramJson(`https://api.telegram.org/bot${tkn}/getWebhookInfo`, 5000),
                shouldRefreshIdentity ? fetchTelegramJson(`https://api.telegram.org/bot${tkn}/getMe`, 5000) : Promise.resolve(null)
            ]);
            if (meData && !meData.ok) {
                setBotStatus({
                    connected: false,
                    loading: false,
                    botName: null,
                    botUsername: null,
                    botId: null,
                    error: meData.description,
                    webhookUrl: null,
                    webhookError: null,
                    webhookErrorAt: null,
                    pendingUpdates: null,
                    lastSyncAt: Date.now()
                });
                return;
            }
            if (meData?.ok) botIdentityChecksRef.current = 0;
            else botIdentityChecksRef.current += 1;
            if (!whData?.ok) {
                throw new Error(whData?.description || "Falha ao consultar webhook");
            }
            const webhookErrorAt = whData.result?.last_error_date ? Number(whData.result.last_error_date) * 1000 : null;
            setBotStatus((prev)=>({
                    connected: true,
                    loading: false,
                    botName: meData?.result?.first_name || prev.botName,
                    botUsername: meData?.result?.username || prev.botUsername,
                    botId: meData?.result?.id ? String(meData.result.id) : prev.botId,
                    error: null,
                    webhookUrl: whData.result?.url || null,
                    webhookError: whData.result?.last_error_message || null,
                    webhookErrorAt,
                    pendingUpdates: whData.result?.pending_update_count ?? null,
                    lastSyncAt: Date.now()
                }));
        } catch (err) {
            if (!options?.silent) {
                setBotStatus({
                    connected: false,
                    loading: false,
                    botName: null,
                    botUsername: null,
                    botId: null,
                    error: err?.message || "Erro de conexão",
                    webhookUrl: null,
                    webhookError: null,
                    webhookErrorAt: null,
                    pendingUpdates: null,
                    lastSyncAt: Date.now()
                });
            } else {
                setBotStatus((prev)=>({
                        ...prev,
                        loading: false,
                        lastSyncAt: Date.now()
                    }));
            }
        } finally{
            botRefreshInFlightRef.current = false;
        }
    }, [
        botStatus.botId,
        fetchTelegramJson,
        globalConfig.telegramBotToken
    ]);
